import React, { useState } from 'react';
import * as Styled from './styles';
import changeDataFunc from '../../helpers/functions/changeCaptchaData';
import initialCaptchaData from '../../helpers/functions/initialCaptchaData';
import { ReactComponent as Reset } from '../../assets/images/Captcha/reset.svg'
import useMobile from '../../helpers/hooks/useMobile';

const Captcha = ({setCaptcha}) => {
    const [randomIconsArray, randomIcon] = initialCaptchaData();
    const [desiredIcon, setDesiredIcon] = useState(randomIcon);
    const [iconsToRender, setIconsToRender] = useState(randomIconsArray);
    const isMobile = useMobile();
    const changeData = () => changeDataFunc(setDesiredIcon, setIconsToRender);


    function onIconClick (title) {
        if (title === desiredIcon) {
            setIconsToRender(iconsToRender.map(item => item.title === title ? {...item, flag: true} : item));
            setCaptcha(true);
        }  else {
            setIconsToRender(iconsToRender.map(item => item.title === title
                ? {...item, error: true, flag: false}
                : {...item, error: false, flag: false}
            ));
            setCaptcha(false);
            setTimeout(() => {
                setIconsToRender(iconsToRender.map(item => { return {...item, flag: false, error: false}}));
                changeData();
            },200)
        }
    }
    
    function onResetClick () {
        changeData();
        setCaptcha(false);
    }
    return (
        <Styled.CaptchaContainer isMobile={isMobile}>
            <Styled.Text>
                Security: <Styled.WhiteText>
                         Click the <Styled.WhiteText style={{fontWeight: '700'}}>{desiredIcon}</Styled.WhiteText>
                    </Styled.WhiteText>
            </Styled.Text>
            <Styled.ImagesContainer>
                {iconsToRender.map(item => 
                    <Styled.FalseImage 
                        error={item.error}
                        flag={item.flag}
                        key={item.title}
                        onClick={()=> onIconClick(item.title)}
                    >
                        {item.icon}
                    </Styled.FalseImage>)}
                    <Styled.ResetButton data-ccursor onClick={onResetClick}><Reset /></Styled.ResetButton>
            </Styled.ImagesContainer>
        </Styled.CaptchaContainer>
    );
};

export default Captcha;