import { ReactComponent as Diamond } from '../../assets/images/Captcha/diamond.svg';
import { ReactComponent as Plane } from '../../assets/images/Captcha/plane.svg';
import { ReactComponent as Boat } from '../../assets/images/Captcha/boat.svg';
import { ReactComponent as Leaf } from '../../assets/images/Captcha/leaf.svg';
import { ReactComponent as Bulb } from '../../assets/images/Captcha/bulb.svg';
import { ReactComponent as Flag } from '../../assets/images/Captcha/flag.svg';
import { ReactComponent as Heart } from '../../assets/images/Captcha/heart.svg';
import { ReactComponent as Cup } from '../../assets/images/Captcha/cup.svg';
import { ReactComponent as Truck } from '../../assets/images/Captcha/truck.svg';
import { ReactComponent as Umbrella } from '../../assets/images/Captcha/umbrella.svg'

function changeData (setDesiredIcon, setIconsToRender) {
    const allIcons = [
        {
            title: 'diamond',
            icon: <Diamond/>,
            flag: false,
            error: false,
        },
        {
            title: 'plane',
            icon: <Plane/>,
            flag: false,
            error: false,
        },
        {
            title: 'boat',
            icon: <Boat/>,
            flag: false,
            error: false,
        },
        {
            title: 'leaf',
            icon: <Leaf/>,
            flag: false,
            error: false,
        },
        {
            title: 'bulb',
            icon: <Bulb/>,
            flag: false,
            error: false,
        },
        {
            title: 'flag',
            icon: <Flag/>,
            flag: false,
            error: false,
        },
        {
            title: 'heart',
            icon: <Heart/>,
            flag: false,
            error: false,
        },
        {
            title: 'cup',
            icon: <Cup/>,
            flag: false,
            error: false,
        },
        {
            title: 'truck',
            icon: <Truck/>,
            flag: false,
            error: false,
        },
        {
            title: 'umbrella',
            icon: <Umbrella/>,
            flag: false,
            error: false,
        },
    ];
    const randomOfFive = Math.floor(Math.random() * (4 - 0 + 1) + 0);
    const setIconsArray = allIcons.sort(() => Math.random() - 0.5).slice(0,5);
    setDesiredIcon(setIconsArray[randomOfFive].title);
    setIconsToRender(setIconsArray);
}

export default changeData;
